import os
import sys
import shutil
import tarfile
import zipfile
import bz2
import gzip

def backup(directory, format):
    if not os.path.isdir(directory):
        print("Error: Directory does not exist")
        return
    
    if format == "tar.gz":
        with tarfile.open(f"{directory}.tar.gz", "w:gz") as tar:
            tar.add(directory)
    elif format == "tar.bz2":
        with tarfile.open(f"{directory}.tar.bz2", "w:bz2") as tar:
            tar.add(directory)
    elif format == "zip":
        with zipfile.ZipFile(f"{directory}.zip", "w") as zip:
            zip.write(directory)
    elif format == "7z":
        with bz2.BZ2File(f"{directory}.7z", "wb") as seven:
            seven.write(directory)
    else:
        print("Error: Unsupported compression format")
        return
    
    shutil.copyfile(f"{directory}.{format}", f"{directory}_backup_{format}")